     var value = entry.value;

     if (key == 'errorMessage') {
       final stringValue = value == null ? '' : value.toString();
       value = stringValue.length > SyncConstants.maxErrorMessageLength
           ? stringValue.substring(0, SyncConstants.maxErrorMessageLength)
           : stringValue;
     }

     cleaned[key] = value;
   }

   return cleaned;
 }
